// tools/build-bundle.mjs
// WHAT: concatenates the ES-module src/*.js files into one classic
// (non-module) script, dist/bundle.js, so the game can be opened directly
// via file:// with no server. WHY: browsers block ES module loading
// (static import, <script type=module src>, and dynamic import()) under
// file:// with a CORS error — verified empirically — but a plain classic
// <script> has never been subject to that restriction in any browser.
//
// This is NOT a general-purpose bundler: it assumes the exact style this
// codebase already uses (named imports only, no default/bare-re-exports,
// one `import {...} from './x.js'` per source module, `export function|
// class|const NAME`). It performs no minification and no dependency
// resolution beyond the explicit order below — src/*.js remains the real
// source (and what test/connectivity.mjs imports as real ES modules);
// this script is a one-time, rerun-by-hand step whenever src/ changes.
//
// Run with: node tools/build-bundle.mjs

import { readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const __dirname = dirname(fileURLToPath(import.meta.url));
const SRC_DIR = join(__dirname, '..', 'src');
const OUT_FILE = join(__dirname, '..', 'dist', 'bundle.js');

// Dependency order: every file after data.js/rng.js/log.js only ever
// imports from files earlier in this list.
const ORDER = [
  'data.js', 'rng.js', 'log.js', 'gridmap.js', 'fpview.js', 'automap.js',
  'party.js', 'monsters.js', 'spells.js', 'combat.js', 'services.js',
  'dungeon.js', 'town.js', 'overworld.js', 'main.js',
];

const IMPORT_RE = /import\s*\{([\s\S]*?)\}\s*from\s*['"]\.\/([\w.]+)\.js['"];?/g;
const EXPORT_DECL_RE = /export\s+(function|class|const)\s+(\w+)/g;

function moduleKey(filename) { return filename.replace(/\.js$/, ''); }

function transform(filename, source) {
  const withoutImports = source.replace(IMPORT_RE, (_match, names, targetFile) => {
    const cleaned = names.split(',').map((n) => n.trim()).filter(Boolean).join(', ');
    return `const { ${cleaned} } = __mod['${moduleKey(targetFile)}'];`;
  });

  const exportedNames = new Set();
  const stripped = withoutImports.replace(EXPORT_DECL_RE, (_match, kind, name) => {
    exportedNames.add(name);
    return `${kind} ${name}`;
  });

  return { body: stripped, exportedNames: [...exportedNames] };
}

function build() {
  const chunks = [];
  chunks.push('// AUTO-GENERATED by tools/build-bundle.mjs — do not edit by hand.');
  chunks.push('// Regenerate with: node tools/build-bundle.mjs');
  chunks.push('(function () {');
  chunks.push('  "use strict";');
  chunks.push('  const __mod = {};');

  for (const filename of ORDER) {
    const source = readFileSync(join(SRC_DIR, filename), 'utf8');
    const { body, exportedNames } = transform(filename, source);
    const key = moduleKey(filename);
    chunks.push(`\n  // ---- src/${filename} ----`);
    chunks.push(`  __mod['${key}'] = (function () {`);
    chunks.push(body);
    if (exportedNames.length) {
      chunks.push(`    return { ${exportedNames.join(', ')} };`);
    }
    chunks.push('  })();');
  }

  chunks.push('\n})();');

  mkdirSync(dirname(OUT_FILE), { recursive: true });
  writeFileSync(OUT_FILE, chunks.join('\n') + '\n', 'utf8');
  console.log(`Wrote ${OUT_FILE}`);
}

build();
